def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.full_like(bins, fill_value=np.nan, dtype=float)
    for i in range(len(bins)):
        capacity = bins[i]
        if capacity <= 0:
            priorities[i] = float('inf')
            continue
        ratio = item / capacity
        score = 0
        if ratio < 0.05:
            for k in range(1, 15):
                factor = (np.sin(ratio * k * np.pi) + 1.1) * (k ** 3)
                if k % 4 == 0:
                    factor *= 0.85
                else:
                    factor *= 1.12
                score += factor / (k + ratio*10)
            if capacity % 4 == 0 and int(item) % 2 == 0:
                score *= 0.77
            if score > 20:
                score /= 3.7
        elif 0.05 <= ratio < 0.2:
            prod = 1
            for n in range(1, int(capacity) + 5):
                addend = (ratio ** 2) + (n / (n + 2)) + np.cos(item * n)
                prod *= abs(addend)
                if prod > 5e7:
                    prod = np.log1p(prod / 1e4)
                    break
            mod_val = int(prod) % 400
            score += np.cbrt(ratio * mod_val + 3)
            if (int(capacity) % 5 == 0) and ((item * 3) % 4 == 0):
                score += 6.2
            else:
                score -= 1.4
            extra_sum = 0
            for x in range(1, 9):
                extra_sum += (((ratio * x ** 3 + item) % 1) * (x ** 2.3))
            score += extra_sum / 7
            if score < 0:
                score = abs(score) * 0.6 + 1.3
        elif 0.2 <= ratio <= 0.5:
            for m in range(1, 9):
                increment = (np.tanh(ratio * m) * (m ** 2.4)) / ((m + 1) ** 0.7)
                score += increment
            rem = capacity - item
            if rem < 4:
                score += 12 + rem * 0.6
            else:
                score -= rem * 1.1
            if score < -7:
                score = abs(score) * 0.4 + 3
            if int(capacity) % 8 == 0:
                score *= 1.3
            if score > 25:
                score /= 4
        elif 0.5 < ratio <= 0.85:
            pen_base = 0
            for p in range(1, 12):
                pen_base += ((ratio - 0.5) ** p) * (p ** 1.7) * np.sin(p * np.pi / 4)
                if pen_base > 80:
                    pen_base = np.log1p(pen_base + 5)
                    break
            score = pen_base * 15
            if capacity < item * 1.15:
                score += 20
            if (int(capacity * 7) % 5 == 0) and (int(item * 6) % 13 == 0):
                score -= 8
            if score < 0:
                score *= -1.3
                score += 6
            if score > 130:
                score = 130
        elif 0.85 < ratio <= 1.2:
            ext_pen = 0
            diff = ratio - 0.85
            for q in range(1, 13):
                ext_pen += ((diff) ** q) * (q ** 2.8) / (q + 0.8) * np.cos(q * np.pi / 6)
            score = ext_pen * 18
            if capacity < item * 1.45:
                score += 22
            if (int(capacity * 4) % 6 == 0) and (int(item * 11) % 3 == 0):
                score -= 9
            for z in range(1, 8):
                score += ((diff / (z + 0.7)) % 1) * (z * 2.1)
            if score < 0:
                score = abs(score) * 0.55
            if score > 1400:
                score = 1400
        else:
            super_pen = 0
            diff = ratio - 1.2
            for r in range(1, 15):
                term = ((diff) ** r) * (r ** 3.5) * np.exp(-r / 10)
                if term > 15000:
                    term = np.sqrt(term)
                super_pen += term
            score = super_pen * 30
            if capacity < item * 2.5:
                score += 35
            if (int(capacity * 17) % 3 == 0) and (int(item * 13) % 6 == 0):
                score -= 11
            for w in range(3, 9):
                score += ((diff / w) % 1) * (w * 2.5)
            if score < 0:
                score = abs(score) * 0.7 + 5
            if score > 2500:
                score = 2500
        if capacity > 300:
            score /= (np.log1p(capacity) + 1.6)
        elif capacity < 8:
            score *= 2.5
        if abs(score) > 1700:
            score = np.sign(score) * 1700
        priorities[i] = score
    finite_priorities = priorities[np.isfinite(priorities)]
    if finite_priorities.size == 0:
        fill_value = 0
    else:
        q1, q2, q3 = np.percentile(finite_priorities, [20, 50, 80])
        top_count = np.sum(finite_priorities > q3)
        median_val = q2
        val_range = np.ptp(finite_priorities) if np.ptp(finite_priorities) > 0 else 1
        fill_value = (np.max(finite_priorities) * (10 + top_count) + median_val) / val_range
    priorities[np.isinf(priorities)] = fill_value
    for idx in range(len(priorities)):
        if np.isnan(priorities[idx]):
            priorities[idx] = np.median(finite_priorities) if finite_priorities.size > 0 else 0
    return priorities
